import sys
import math
from collections import Counter


def solve():
    n, x = map(int, input().split())
    s = input()

    pre_0 = [0]
    pre_1 = [0]
    for i in range(n):
        if s[i] == "0":
            pre_0.append(pre_0[-1] + 1)
            pre_1.append(pre_1[-1])
        else:
            pre_0.append(pre_0[-1])
            pre_1.append(pre_1[-1] + 1)

    cnt = Counter()
    for i in range(n):
        cnt[pre_0[i + 1] - pre_1[i + 1]] += 1

    ans = 0
    for i in range(n + 1):
        if pre_0[i] - pre_1[i] == x:
            ans += 1
        if x - pre_0[i] + pre_1[i] in cnt:
            ans += cnt[x - pre_0[i] + pre_1[i]]

    print(ans)


if __name__ == '__main__':
    t = int(input())
    for _ in range(t):
        solve()
